        }}
      >
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <h1 style={{ margin: 0, fontSize: "1.25rem", color: "#fff" }}>
            Chat with Mira
          </h1>
          <span
            style={{
              fontSize: "0.75rem",
              color: connected ? "#4caf50" : "#f44336",
