            disabled={sessionActive}
            style={btnStyle(sessionActive ? "#333" : "#16a34a")}
          >
            Start Session
          </button>
          <button
            onClick={endSession}
            disabled={!sessionActive}
            style={btnStyle(!sessionActive ? "#333" : "#dc2626")}
          >
            End Session
          </button>
        </div>
      </div>

      {/* Messages */}
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          padding: "16px 20px",
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        {messages.map((msg) => (
          <div
            key={msg.id}
            style={{
              alignSelf:
                msg.role === "user"
                  ? "flex-end"
                  : msg.role === "system"
                  ? "center"
                  : "flex-start",
              maxWidth: msg.role === "system" ? "90%" : "80%",
              padding: "10px 14px",
              borderRadius: 12,
              fontSize: "0.9rem",
