              border: "1px solid #2a2a4e",
              borderRadius: 8,
              cursor: sessionActive ? "pointer" : "default",
              opacity: sessionActive ? 1 : 0.4,
            }}
          >
            {emoji}
          </button>
        ))}
      </div>

      {/* Text input */}
      <div
        style={{
          display: "flex",
          gap: 8,
          padding: "12px 20px 20px",
          borderTop: "1px solid #222",
        }}
      >
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
          placeholder={sessionActive ? "Type a message..." : "Start a session first"}
          disabled={!sessionActive}
          style={{
            flex: 1,
            padding: "10px 14px",
            background: "#1a1a1a",
            border: "1px solid #333",
            borderRadius: 8,
            color: "#e0e0e0",
            fontSize: "0.9rem",
            opacity: sessionActive ? 1 : 0.5,
          }}
        />
        <button
          onClick={sendMessage}
          disabled={!sessionActive || !input.trim()}
          style={btnStyle(!sessionActive || !input.trim() ? "#333" : "#6b21a8")}
        >
          Send
        </button>
      </div>
    </main>
  );
}

function btnStyle(bg: string): React.CSSProperties {
  return {
    padding: "8px 16px",
    background: bg,
    color: "#fff",
    border: "none",
    borderRadius: 6,
    cursor: bg === "#333" ? "default" : "pointer",
    fontSize: "0.85rem",
    fontWeight: 600,
    whiteSpace: "nowrap",
  };
}

