        event: { type: "gesture", gesture },
      });
    },
    [userId]
  );

  return (
    <main
      style={{
        maxWidth: 640,
        margin: "0 auto",
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        background: "#0a0a0a",
        color: "#e0e0e0",
        fontFamily: "system-ui, -apple-system, sans-serif",
      }}
    >
      {/* Header */}
      <div
        style={{
          padding: "16px 20px",
          borderBottom: "1px solid #222",
          display: "flex",
          flexDirection: "column",
          gap: 10,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <h1 style={{ margin: 0, fontSize: "1.25rem", color: "#fff" }}>
            Chat with Mira
          </h1>
          <span
            style={{
              fontSize: "0.75rem",
              color: connected ? "#4caf50" : "#f44336",
            }}
          >
            {connected ? "Connected" : "Disconnected"}
          </span>
        </div>

        {/* User ID + Join */}
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          <input
            type="text"
            value={userId}
            onChange={(e) => setUserId(e.target.value)}
            placeholder="User ID (UUID)"
            style={{
              flex: 1,
              padding: "6px 10px",
              background: "#1a1a1a",
              border: "1px solid #333",
              borderRadius: 6,
              color: "#e0e0e0",
              fontSize: "0.8rem",
            }}
          />
          <button onClick={joinRoom} style={btnStyle("#6b21a8")}>
            Join
          </button>
        </div>

        {/* Session controls */}
        <div style={{ display: "flex", gap: 8 }}>
          <button
            onClick={startSession}
            disabled={sessionActive}
            style={btnStyle(sessionActive ? "#333" : "#16a34a")}
          >
            Start Session
          </button>
          <button
            onClick={endSession}
            disabled={!sessionActive}
            style={btnStyle(!sessionActive ? "#333" : "#dc2626")}
          >
            End Session
          </button>
        </div>
      </div>

      {/* Messages */}
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          padding: "16px 20px",
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        {messages.map((msg) => (
          <div
            key={msg.id}
            style={{
              alignSelf:
                msg.role === "user"
                  ? "flex-end"
                  : msg.role === "system"
                  ? "center"
                  : "flex-start",
              maxWidth: msg.role === "system" ? "90%" : "80%",
              padding: "10px 14px",
