        ...prev,
        { id: `user-${Date.now()}`, role: "user", text: `[${label}]` },
      ]);
      socket.emit("mirror_event", {
        user_id: userId,
        event: { type: "gesture", gesture },
      });
    },
    [userId]
  );

  return (
    <main
      style={{
        maxWidth: 640,
        margin: "0 auto",
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        background: "#0a0a0a",
        color: "#e0e0e0",
        fontFamily: "system-ui, -apple-system, sans-serif",
      }}
    >
      {/* Header */}
      <div
        style={{
          padding: "16px 20px",
          borderBottom: "1px solid #222",
          display: "flex",
          flexDirection: "column",
          gap: 10,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <h1 style={{ margin: 0, fontSize: "1.25rem", color: "#fff" }}>
            Chat with Mira
          </h1>
          <span
            style={{
              fontSize: "0.75rem",
              color: connected ? "#4caf50" : "#f44336",
            }}
          >
            {connected ? "Connected" : "Disconnected"}
          </span>
        </div>

        {/* User ID + Join */}
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          <input
            type="text"
            value={userId}
            onChange={(e) => setUserId(e.target.value)}
            placeholder="User ID (UUID)"
            style={{
              flex: 1,
              padding: "6px 10px",
              background: "#1a1a1a",
              border: "1px solid #333",
              borderRadius: 6,
              color: "#e0e0e0",
              fontSize: "0.8rem",
            }}
          />
          <button onClick={joinRoom} style={btnStyle("#6b21a8")}>
            Join
          </button>
        </div>

        {/* Session controls */}
        <div style={{ display: "flex", gap: 8 }}>
          <button
            onClick={startSession}
            disabled={sessionActive}
            style={btnStyle(sessionActive ? "#333" : "#16a34a")}
          >
            Start Session
          </button>
          <button
            onClick={endSession}
            disabled={!sessionActive}
            style={btnStyle(!sessionActive ? "#333" : "#dc2626")}
          >
            End Session
          </button>
        </div>
      </div>

      {/* Messages */}
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          padding: "16px 20px",
          display: "flex",
          flexDirection: "column",
          gap: 12,
        }}
      >
        {messages.map((msg) => (
          <div
            key={msg.id}
            style={{
              alignSelf:
                msg.role === "user"
                  ? "flex-end"
                  : msg.role === "system"
                  ? "center"
                  : "flex-start",
              maxWidth: msg.role === "system" ? "90%" : "80%",
              padding: "10px 14px",
              borderRadius: 12,
              fontSize: "0.9rem",
              lineHeight: 1.5,
              whiteSpace: "pre-wrap",
              ...(msg.role === "user"
                ? { background: "#6b21a8", color: "#fff" }
                : msg.role === "mira"
                ? { background: "#1a1a2e", color: "#e0e0e0", border: "1px solid #2a2a4e" }
                : { background: "#111", color: "#888", fontSize: "0.8rem", fontStyle: "italic" }),
            }}
          >
            {msg.role === "mira" && (
              <div style={{ fontSize: "0.7rem", color: "#9b59b6", marginBottom: 4, fontWeight: 600 }}>
                Mira
              </div>
            )}
            {msg.text}
          </div>
        ))}

        {/* Product cards */}
        {products.map((card) => (
          <div key={card.id} style={{ alignSelf: "flex-start", maxWidth: "90%" }}>
            <div style={{ fontSize: "0.75rem", color: "#888", marginBottom: 6 }}>
              Results for &quot;{card.query}&quot;
            </div>
            <div style={{ display: "flex", gap: 10, overflowX: "auto", paddingBottom: 4 }}>
              {card.items.map((item, i) => (
                <a
                  key={i}
                  href={item.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  style={{
                    minWidth: 160,
                    background: "#1a1a2e",
                    border: "1px solid #2a2a4e",
                    borderRadius: 10,
                    padding: 10,
                    textDecoration: "none",
                    color: "#e0e0e0",
                    display: "flex",
                    flexDirection: "column",
                    gap: 6,
                  }}
                >
                  {item.image_url && (
                    <img
                      src={item.image_url}
                      alt={item.title}
                      style={{
                        width: "100%",
                        height: 120,
                        objectFit: "contain",
                        borderRadius: 6,
                        background: "#fff",
                      }}
                    />
                  )}
                  <div style={{ fontSize: "0.8rem", fontWeight: 600 }}>
                    {item.title.length > 50 ? item.title.slice(0, 50) + "..." : item.title}
                  </div>
                  <div style={{ fontSize: "0.85rem", color: "#9b59b6", fontWeight: 700 }}>
                    {item.price}
                  </div>
                  <div style={{ fontSize: "0.7rem", color: "#888" }}>
                    {item.source}
                    {item.rating ? ` | ${item.rating}★` : ""}
                  </div>
                </a>
              ))}
            </div>
          </div>
        ))}

        <div ref={messagesEndRef} />
      </div>

      {/* Gesture buttons */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: 12,
          padding: "8px 20px",
          borderTop: "1px solid #222",
        }}
      >
        {[
          { gesture: "thumbs_up", label: "Thumbs Up", emoji: "\ud83d\udc4d" },
          { gesture: "thumbs_down", label: "Thumbs Down", emoji: "\ud83d\udc4e" },
          { gesture: "swipe_left", label: "Swipe Left", emoji: "\u2b05\ufe0f" },
          { gesture: "swipe_right", label: "Swipe Right", emoji: "\u27a1\ufe0f" },
        ].map(({ gesture, label, emoji }) => (
          <button
            key={gesture}
            onClick={() => sendGesture(gesture, label)}
            disabled={!sessionActive}
            title={label}
            style={{
              padding: "8px 16px",
              fontSize: "1.3rem",
              background: sessionActive ? "#1a1a2e" : "#111",
              border: "1px solid #2a2a4e",
              borderRadius: 8,
              cursor: sessionActive ? "pointer" : "default",
              opacity: sessionActive ? 1 : 0.4,
            }}
          >
            {emoji}
          </button>
        ))}
      </div>

      {/* Text input */}
      <div
        style={{
          display: "flex",
          gap: 8,
          padding: "12px 20px 20px",
          borderTop: "1px solid #222",
        }}
      >
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
          placeholder={sessionActive ? "Type a message..." : "Start a session first"}
          disabled={!sessionActive}
          style={{
            flex: 1,
            padding: "10px 14px",
            background: "#1a1a1a",
            border: "1px solid #333",
            borderRadius: 8,
            color: "#e0e0e0",
            fontSize: "0.9rem",
            opacity: sessionActive ? 1 : 0.5,
          }}
        />
        <button
          onClick={sendMessage}
          disabled={!sessionActive || !input.trim()}
          style={btnStyle(!sessionActive || !input.trim() ? "#333" : "#6b21a8")}
        >
          Send
        </button>
      </div>
    </main>
  );
}

function btnStyle(bg: string): React.CSSProperties {
  return {
    padding: "8px 16px",
    background: bg,
    color: "#fff",
    border: "none",
    borderRadius: 6,
    cursor: bg === "#333" ? "default" : "pointer",
    fontSize: "0.85rem",
    fontWeight: 600,
    whiteSpace: "nowrap",
  };
}

